static size_t descriptor_buffer_descriptor_size(VkPhysicalDevice physical_device, VkDescriptorType type)
{
	if (physical_device == VK_NULL_HANDLE) return 0;

	VkPhysicalDeviceDescriptorBufferPropertiesEXT props = { VK_STRUCTURE_TYPE_PHYSICAL_DEVICE_DESCRIPTOR_BUFFER_PROPERTIES_EXT, nullptr };
	VkPhysicalDeviceProperties2 props2 = { VK_STRUCTURE_TYPE_PHYSICAL_DEVICE_PROPERTIES_2, &props };
	wrap_vkGetPhysicalDeviceProperties2(physical_device, &props2);

	switch (type)
	{
	case VK_DESCRIPTOR_TYPE_SAMPLER: return props.samplerDescriptorSize;
	case VK_DESCRIPTOR_TYPE_COMBINED_IMAGE_SAMPLER: return props.combinedImageSamplerDescriptorSize;
	case VK_DESCRIPTOR_TYPE_SAMPLED_IMAGE: return props.sampledImageDescriptorSize;
	case VK_DESCRIPTOR_TYPE_STORAGE_IMAGE: return props.storageImageDescriptorSize;
	case VK_DESCRIPTOR_TYPE_UNIFORM_TEXEL_BUFFER: return props.uniformTexelBufferDescriptorSize;
	case VK_DESCRIPTOR_TYPE_STORAGE_TEXEL_BUFFER: return props.storageTexelBufferDescriptorSize;
	case VK_DESCRIPTOR_TYPE_UNIFORM_BUFFER: return props.uniformBufferDescriptorSize;
	case VK_DESCRIPTOR_TYPE_STORAGE_BUFFER: return props.storageBufferDescriptorSize;
	case VK_DESCRIPTOR_TYPE_INPUT_ATTACHMENT: return props.inputAttachmentDescriptorSize;
	case VK_DESCRIPTOR_TYPE_ACCELERATION_STRUCTURE_KHR: return props.accelerationStructureDescriptorSize;
	default: return 0;
	}
}

static VkPhysicalDevice descriptor_buffer_physical_device(lava_file_reader& reader, VkDevice device)
{
	VkPhysicalDevice physical_device = reader.physicalDevice;
	if (physical_device == VK_NULL_HANDLE && device != VK_NULL_HANDLE)
	{
		const uint32_t device_index = index_to_VkDevice.index(device);
		physical_device = VkDevice_index.at(device_index).physicalDevice;
	}
	return physical_device;
}

[[noreturn]] static void skip_descriptor_buffer_portability(lava_file_reader& reader, VkDescriptorType descriptor_type, size_t capture_size,
	size_t replay_size, uint64_t offset = 0, uint64_t region_size = 0)
{
	const std::string descriptor_name = VkDescriptorType_to_string(descriptor_type);
	if (region_size != 0)
	{
		printf("SKIP: descriptor buffer portability unsupported while replaying %s at thread=%u call=%u frame=%u: replay device requires %zu bytes, "
			"but the captured marked region only provides %zu bytes at offset %lu in a %lu-byte update.\n",
			descriptor_name.c_str(), reader.current.thread, reader.current.call, reader.current.frame, replay_size, capture_size,
			(unsigned long)offset, (unsigned long)region_size);
	}
	else
	{
		printf("SKIP: descriptor buffer portability unsupported while replaying %s at thread=%u call=%u frame=%u: replay device requires %zu bytes, "
			"but the trace captured only %zu bytes.\n",
			descriptor_name.c_str(), reader.current.thread, reader.current.call, reader.current.frame, replay_size, capture_size);
	}
	printf("SKIP: capture and replay across devices with different descriptor-buffer sizes is not supported for this trace.\n");
	reader.parent->exit_status = 77;
	reader.parent->request_stop(reader.device);
	reader.throw_stop_requested();
}

static void queue_descriptor_rewrite(lava_file_reader& reader, VkPhysicalDevice physical_device, VkDescriptorType descriptor_type,
	const void* capture_bytes, const void* replay_bytes, size_t data_size)
{
	size_t descriptor_size = descriptor_buffer_descriptor_size(physical_device, descriptor_type);
	if (descriptor_size == 0) descriptor_size = data_size;
	if (descriptor_size == 0) return;
	if (data_size != 0 && descriptor_size > data_size)
	{
		skip_descriptor_buffer_portability(reader, descriptor_type, data_size, descriptor_size);
	}

	descriptor_rewrite rewrite;
	rewrite.type = descriptor_type;
	rewrite.capture_bytes.resize(descriptor_size);
	rewrite.bytes.resize(descriptor_size);
	rewrite.source = reader.current;
	memcpy(rewrite.capture_bytes.data(), capture_bytes ? capture_bytes : replay_bytes, descriptor_size);
	memcpy(rewrite.bytes.data(), replay_bytes ? replay_bytes : capture_bytes, descriptor_size);

	lava::lock_guard lock(sync_mutex);
	reader.parent->pending_descriptor_rewrites.push_back(std::move(rewrite));
}

void replay_callback_vkGetDescriptorEXT(callback_context& cb, VkDevice device, const VkDescriptorGetInfoEXT* pDescriptorInfo, size_t dataSize, void* pDescriptor)
{
	if (!cb.reader.run || !pDescriptorInfo || !pDescriptor || device == VK_NULL_HANDLE) return;

	const VkPhysicalDevice physical_device = descriptor_buffer_physical_device(cb.reader, device);

	size_t descriptor_size = descriptor_buffer_descriptor_size(physical_device, pDescriptorInfo->type);
	if (descriptor_size == 0) descriptor_size = dataSize;
	if (descriptor_size == 0) return;
	if (dataSize != 0 && descriptor_size > dataSize)
	{
		skip_descriptor_buffer_portability(cb.reader, pDescriptorInfo->type, dataSize, descriptor_size);
	}

	std::vector<uint8_t> replay_bytes(descriptor_size);
	wrap_vkGetDescriptorEXT(device, pDescriptorInfo, descriptor_size, replay_bytes.data());
	queue_descriptor_rewrite(cb.reader, physical_device, pDescriptorInfo->type, pDescriptor, replay_bytes.data(), dataSize);
}

void replay_callback_vkWriteSamplerDescriptorsEXT(callback_context& cb, VkDevice device, uint32_t samplerCount, const VkSamplerCreateInfo* pSamplers,
	const VkHostAddressRangeEXT* pDescriptors)
{
	(void)pSamplers;
	if (cb.result.vkresult != VK_SUCCESS || !cb.reader.run || device == VK_NULL_HANDLE || !pDescriptors) return;

	const VkPhysicalDevice physical_device = descriptor_buffer_physical_device(cb.reader, device);
	for (uint32_t i = 0; i < samplerCount; i++)
	{
		if (!pDescriptors[i].address || pDescriptors[i].size == 0) continue;
		queue_descriptor_rewrite(cb.reader, physical_device, VK_DESCRIPTOR_TYPE_SAMPLER, pDescriptors[i].address, pDescriptors[i].address, pDescriptors[i].size);
	}
}

void replay_callback_vkWriteResourceDescriptorsEXT(callback_context& cb, VkDevice device, uint32_t resourceCount, const VkResourceDescriptorInfoEXT* pResources,
	const VkHostAddressRangeEXT* pDescriptors)
{
	if (cb.result.vkresult != VK_SUCCESS || !cb.reader.run || device == VK_NULL_HANDLE || !pResources || !pDescriptors) return;

	const VkPhysicalDevice physical_device = descriptor_buffer_physical_device(cb.reader, device);
	for (uint32_t i = 0; i < resourceCount; i++)
	{
		if (!pDescriptors[i].address || pDescriptors[i].size == 0) continue;
		queue_descriptor_rewrite(cb.reader, physical_device, pResources[i].type, pDescriptors[i].address, pDescriptors[i].address, pDescriptors[i].size);
	}
}

