void retrace_vkEnumerateInstanceLayerProperties(lava_file_reader& reader)
{
	// Declarations
	std::vector<VkLayerProperties> pProperties;
	uint32_t pPropertyCount = 0;
	// Load
	uint8_t do_call = reader.read_uint8_t();
	// Execute
	VkResult retval = VK_RESULT_MAX_ENUM;
	if (do_call == 1 && reader.run)
	{
		retval = wrap_vkEnumerateInstanceLayerProperties(&pPropertyCount, nullptr);
		assert(retval == VK_SUCCESS);
		pProperties.resize(pPropertyCount);
		retval = wrap_vkEnumerateInstanceLayerProperties(&pPropertyCount, pProperties.data());
		assert(retval == VK_SUCCESS);
		(void)retval; // ignore return value
	}
	VkResult stored_retval = static_cast<VkResult>(reader.read_uint32_t());
	if (retval == VK_RESULT_MAX_ENUM) retval = stored_retval;
	// Post
	callback_context cb_context{ reader };
	cb_context.result.vkresult = retval;
	VkLayerProperties tool_property = {};
	uint32_t* pPropertyCount_ptr = (do_call == 1) ? &pPropertyCount : nullptr;
	VkLayerProperties* pProperties_ptr = nullptr;
	if (do_call == 1)
	{
		pProperties_ptr = reader.run ? pProperties.data() : &tool_property;
	}
	for (auto* c : vkEnumerateInstanceLayerProperties_callbacks) c(cb_context, pPropertyCount_ptr, pProperties_ptr);
	if (reader.parent->print_packets) print_params_publish(cb_context, json_params_vkEnumerateInstanceLayerProperties(cb_context));
	while (check_cli(cb_context)) cli_params_vkEnumerateInstanceLayerProperties(cb_context);
}

